#!/bin/sh
#
# Get GCP Access Token (OIDC) using GCP Workload Identity Federation (WIF)
#
# Reads the following environment variables:
# - Stored in GitLab CI/CD variables:
#   - 'GCP_WORKLOAD_IDENTITY_FEDERATION_PROJECT_ID': The Google Cloud project ID where the Workload Identity Pool is configured.
#   - 'GCP_WORKLOAD_IDENTITY_FEDERATION_POOL_ID': The ID of the Workload Identity Pool within the specified Google Cloud project.
#   - 'GCP_WORKLOAD_IDENTITY_FEDERATION_PROVIDER_ID': The ID of the Workload Identity Provider within the specified pool.
# - Generated by GitLab CI/CD job in id_tokens section (https://docs.gitlab.com/ci/secrets/id_token_authentication/):
#   - 'GCP_ID_TOKEN': An OIDC identity token issued by a trusted identity provider (IdP), here, GitLab.com.
#
# Output:
# - stdout: The GCP WIF access token (only output on success).

set -eu

readonly GCP_STS_ENDPOINT="https://sts.googleapis.com/v1/token"
readonly CURL_MAX_TIME=30
readonly CURL_RETRIES=3

##############################################
# Validate required environment variables    #
##############################################

for var in \
  GCP_WORKLOAD_IDENTITY_FEDERATION_PROJECT_ID \
  GCP_WORKLOAD_IDENTITY_FEDERATION_POOL_ID \
  GCP_WORKLOAD_IDENTITY_FEDERATION_PROVIDER_ID \
  GCP_ID_TOKEN; do
  eval "val=\${${var}:-}"
  if [ -z "${val}" ]; then
    echo "ERROR: Required environment variable '${var}' is not set." >&2
    exit 1
  fi
done

echo "GCP WIF access token generation..." >&2

####################################################
# Generate the payload asking for the access token #
####################################################

# Disable debug mode to prevent leaking sensitive values
{ set +x; } 2> /dev/null

FEDERATION_PAYLOAD=$(
  cat << EOF
{
  "audience": "//iam.googleapis.com/projects/${GCP_WORKLOAD_IDENTITY_FEDERATION_PROJECT_ID}/locations/global/workloadIdentityPools/${GCP_WORKLOAD_IDENTITY_FEDERATION_POOL_ID}/providers/${GCP_WORKLOAD_IDENTITY_FEDERATION_PROVIDER_ID}",
  "grantType": "urn:ietf:params:oauth:grant-type:token-exchange",
  "requestedTokenType": "urn:ietf:params:oauth:token-type:access_token",
  "scope": "https://www.googleapis.com/auth/cloud-platform",
  "subjectTokenType": "urn:ietf:params:oauth:token-type:jwt",
  "subjectToken": "${GCP_ID_TOKEN}"
}
EOF
)

#####################################################
# Exchange the GCP ID token against an access token #
#####################################################

ACCESS_TOKEN_RESPONSE=$(
  printf '%s' "${FEDERATION_PAYLOAD}" |
    curl --silent --fail --show-error \
      --max-time "${CURL_MAX_TIME}" \
      --retry "${CURL_RETRIES}" \
      -X POST "${GCP_STS_ENDPOINT}" \
      --header "Accept: application/json" \
      --header "Content-Type: application/json" \
      --data @-
) || {
  echo "ERROR: HTTP request to ${GCP_STS_ENDPOINT} failed (curl exit code: $?)." >&2
  exit 1
}

##############################################
# Extract and validate the access token      #
##############################################

ACCESS_TOKEN=$(echo "${ACCESS_TOKEN_RESPONSE}" | jq -er '.access_token' 2> /dev/null) || {
  echo "WORKLOAD IDENTITY FEDERATION ERROR" >&2
  echo "Error type: $(echo "${ACCESS_TOKEN_RESPONSE}" | jq -r '.error // "unknown"')" >&2
  echo "Error description: $(echo "${ACCESS_TOKEN_RESPONSE}" | jq -r '.error_description // "no description"')" >&2
  exit 1
}

if [ -z "${ACCESS_TOKEN}" ]; then
  echo "ERROR: Extracted access token is empty." >&2
  exit 1
fi

##############################################
# Write the token to stdout                  #
##############################################

echo "${ACCESS_TOKEN}"

echo "GCP WIF access token generated: access granted." >&2

exit 0
